def self_consistency_vote(paths):
    counts = {}
    for p in paths:
        ans = p.split()[-1]
        counts[ans] = counts.get(ans, 0) + 1
    return max(counts, key=counts.get)

def run_practice():
    paths = ['Answer is 4', 'Answer is 2', 'Answer is 4']
    assert self_consistency_vote(paths) == '4'
    print('[PASS] Self-consistency voting checks succeeded.')

if __name__ == '__main__':
    run_practice()
